import { Link } from 'react-router-dom';
import { FaThumbsUp, FaComment, FaEye, FaCheckCircle } from 'react-icons/fa';
import Avatar from './Avatar';
import dayjs from 'dayjs';
import relativeTime from 'dayjs/plugin/relativeTime';

dayjs.extend(relativeTime);

function ForumPostCard({ post }) {
  const {
    _id,
    title,
    description,
    author,
    createdAt,
    updatedAt,
    upvotes,
    downvotes,
    comments,
    views,
    category,
    tags,
    hasSolution
  } = post;

  // Truncate description for preview
  const truncateText = (text, maxLength = 150) => {
    if (!text || text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  };

  return (
    <div className="bg-white rounded-lg shadow-sm hover:shadow-md transition-shadow border border-gray-100 overflow-hidden">
      <Link to={`/forum/post/${_id}`} className="block">
        <div className="p-4">
          <div className="flex justify-between items-start mb-2">
            <div>
              <h3 className="text-lg font-semibold text-gray-800 hover:text-green-600 mb-1">
                {title}
              </h3>
              
              <div className="flex flex-wrap items-center mb-2">
                {category && (
                  <span className="inline-block bg-green-100 text-green-800 text-xs px-2 py-1 rounded mr-2 mb-1">
                    {category}
                  </span>
                )}
                
                {hasSolution && (
                  <span className="inline-flex items-center bg-teal-100 text-teal-800 text-xs px-2 py-1 rounded mr-2 mb-1">
                    <FaCheckCircle className="mr-1" size={12} /> Solved
                  </span>
                )}
                
                {tags && tags.slice(0, 3).map(tag => (
                  <span key={tag} className="inline-block bg-gray-100 text-gray-800 text-xs px-2 py-1 rounded mr-2 mb-1">
                    {tag}
                  </span>
                ))}
                
                {tags && tags.length > 3 && (
                  <span className="inline-block text-xs text-gray-500 mb-1">
                    +{tags.length - 3} more
                  </span>
                )}
              </div>
            </div>
          </div>
          
          {description && (
            <p className="text-gray-600 text-sm mb-3 line-clamp-2">
              {truncateText(description)}
            </p>
          )}
          
          <div className="flex items-center justify-between mt-3 pt-3 border-t border-gray-100">
            <div className="flex items-center">
              <Avatar 
                name={author?.name || 'User'} 
                image={author?.avatar} 
                size="xs" 
              />
              <div className="ml-2">
                <span className="text-sm font-medium text-gray-700">
                  {author?.name || 'Anonymous'}
                </span>
                <div className="text-xs text-gray-500">
                  {dayjs(createdAt).fromNow()}
                  {createdAt !== updatedAt && ' (edited)'}
                </div>
              </div>
            </div>
            
            <div className="flex items-center space-x-3 text-xs text-gray-500">
              <div className="flex items-center">
                <FaThumbsUp className="mr-1" size={12} />
                <span>{upvotes || 0}</span>
              </div>
              <div className="flex items-center">
                <FaComment className="mr-1" size={12} />
                <span>{comments?.length || 0}</span>
              </div>
              <div className="flex items-center">
                <FaEye className="mr-1" size={12} />
                <span>{views || 0}</span>
              </div>
            </div>
          </div>
        </div>
      </Link>
    </div>
  );
}

export default ForumPostCard;
